//-------------------------------------------------------------------------
// 팝업결과
//  flag : 신규 추가. 어떤 팝업을 호출했는지 구분
//  1:작성부서From,2:작성부서To(미사용),3:작성자,4:전표종류,5:회계처리자
//-------------------------------------------------------------------------
scwin.f_resultPopEd = function (strCd,strNm,rtnList, flag){
    console.log("=== f_resultPopEd (팝업결과)   flag ["+flag+"]  1:작성부서From,2:작성부서To(미사용),3:작성자,4:전표종류,5:회계처리자)");

	if (rtnList != null ) {
		if (rtnList[0] == "N/A") {
            // 히든값 분기처리
            switch (flag){
                case '1'  : scwin.ed_slipAcctDeptCdSt_hidVal = ""; break;  // 작성부서From
                case '3'  : scwin.ed_drawEmpNo_hidVal        = ""; break;  // 작성자
                case '4'  : scwin.ed_slipKndCd_hidVal        = ""; break;  // 전표종류
                case '5'  : scwin.ed_postEmpNo_hidVal        = ""; break;  // 회계처리자
                default   : break;
            }            
			return;
		}
		// strCd.Text = rtnList[0];	// 코드
		// strNm.value = rtnList[1];	// 명
        // strCd.hidVal = rtnList[0];  // 히든값

		strCd.setValue(rtnList[0]);	// 코드
		strNm.setValue(rtnList[1]);	// 명

        // 히든값 분기처리
        switch (flag){
            case '1'  : scwin.ed_slipAcctDeptCdSt_hidVal = rtnList[0]; break;  // 작성부서From
            case '3'  : scwin.ed_drawEmpNo_hidVal        = rtnList[0]; break;  // 작성자
            case '4'  : scwin.ed_slipKndCd_hidVal        = rtnList[0]; break;  // 전표종류
            case '5'  : scwin.ed_postEmpNo_hidVal        = rtnList[0]; break;  // 회계처리자
            default   : break;
        }
	}else{
		// strCd.Text = "";
		// strNm.value = "";
		// strCd.hidVal = "";
	    strCd.setValue( "" );
		strNm.setValue( "" );

        // 히든값 분기처리
        switch (flag){
            case '1'  : scwin.ed_slipAcctDeptCdSt_hidVal = ""; break;  // 작성부서From
            case '3'  : scwin.ed_drawEmpNo_hidVal        = ""; break;  // 작성자
            case '4'  : scwin.ed_slipKndCd_hidVal        = ""; break;  // 전표종류
            case '5'  : scwin.ed_postEmpNo_hidVal        = ""; break;  // 회계처리자
            default   : break;
        }
	}
};

//-------------------------------------------------------------------------
// 팝업체크 - 코드값 변경시 자동검색
//   flag : 팝업 플래그
//-------------------------------------------------------------------------
//  1:작성부서From,2:작성부서To(미사용),3:작성자,4:전표종류,5:회계처리자
scwin.f_checkPopEd = function(strCd,strNm,flag){
    console.log("===== f_checkPopEd (팝업체크 - 코드값 변경시 자동검색  srtCd["+strCd+"] strNm["+strNm.getValue()+"] flag["+flag+"]");

	// if (strCd.text.trim() == strCd.hidVal)
	// 	return;

	if ( ( flag=='1'  && (strCd.getValue().trim() == scwin.ed_slipAcctDeptCdSt_hidVal )) ||  // 작성부서From
         ( flag=='3'  && (strCd.getValue().trim() == scwin.ed_drawEmpNo_hidVal        )) ||  // 작성자
         ( flag=='4'  && (strCd.getValue().trim() == scwin.ed_slipKndCd_hidVal        )) ||  // 전표종류
         ( flag=='5'  && (strCd.getValue().trim() == scwin.ed_postEmpNo_hidVal        ))     // 회계처리자
	    ) {
        // KYU_TEST : 히든 비교시 코드가 null 이 아니어야 함. (코드 null 일 때 명 null 처리)
        if ( strCd.getValue() != "" ) return;
	}

	// strNm.value="";
    strNm.setValue("");

	// strCd.hidVal="";
    switch (flag){
        case '1'  : scwin.ed_slipAcctDeptCdSt_hidVal = ""; break;  // 작성부서From
        case '3'  : scwin.ed_drawEmpNo_hidVal        = ""; break;  // 작성자
        case '4'  : scwin.ed_slipKndCd_hidVal        = ""; break;  // 전표종류
        case '5'  : scwin.ed_postEmpNo_hidVal        = ""; break;  // 회계처리자
        default   : break;
    }

	if(strCd.getValue().trim()!="")
		scwin.f_openPopUp(flag,'T');
};


