//-------------------------------------------------------------------------
// 부가세번호 체크
//-------------------------------------------------------------------------
scwin.getVatNo = function(slipNo) {
    console.log("=== getVatNo (부가세번호 체크");

    ds_commonCode.removeAll();

    // SELECT 절
	var param1 = "VAT_NO AS COL1 ,''  AS COL2 ,'' AS COL3 ,'' AS COL4 ,'' AS COL5 ,'' AS COL6 ,'' AS COL7 ,'' AS COL8 ,'' AS COL9 ,'' AS COL10 ";

	// 대상테이블
	var param2 =
		  "(SELECT SELL_VAT_NO AS VAT_NO "
		+ "   FROM TB_FI301 "
		+ "  WHERE SLIP_NO = '" + slipNo + "'"
		+ "	   AND DEL_YN = 0 "
		+ "  UNION ALL "
		+ " SELECT PCHS_EVID_NO AS VAT_NO "
		+ "   FROM TB_FI304 "
		+ "  WHERE SLIP_NO = '" + slipNo + "'"
		+ "	   AND DEL_YN = 0) "
		;

	// 조건절
    var param3 = " AND 1=1 ";

	// 정렬
	var param4 = " COL1 ";

	// ds_getVatNo.DataId =
	// 	"/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC&queryId=dinymicQueryTest" + "&param1=" + param1
	// 	                                                                             + "&param2=" + param2
	// 	                                                                             + "&param3=" + param3
	// 	                                                                             + "&param4=" + param4;
	// ds_getVatNo.Reset();

	const strParam = {
              sysCd              : "CommonEBC"           // 시스템코드
            , queryId            : "dinymicQueryTest"    // 쿼리ID
            , param1             : param1                // SELECT
            , param2             : param2                // 대상테이블
            , param3             : param3                // 조건절
            , param4             : param4                // CD
            };

    //데이터셋에 정보설정
    ds_commonCode.setJSON(strParam);

    $c.sbm.execute(sbm_getVatNo);
};

//-------------------------------------------------------------------------
// 부가세번호 체크 submitdone
//-------------------------------------------------------------------------
scwin.sbm_getVatNo_submitdone = function (e) {
    console.log("▷ sbm_getVatNo_submitdone (부가세번호 체크 submitdone)");

    if( e.responseJSON.resultDataSet[0].Code != 0 ) return;

    if(e.responseJSON.GAUCE) {
        ds_getVatNo.setJSON(e.responseJSON.GAUCE);
    }
};


//-------------------------------------------------------------------------
// KT-NET 응답 메시지 체크
//-------------------------------------------------------------------------
scwin.getResposeMessage = function(vatNo) {
    console.log("=== getResposeMessage (KT-NET 응답 메시지 체크");

    ds_commonCode.removeAll();

    // SELECT 절
	var param1 =
		  " DISTINCT A.RESPONSETYPE 		AS COL1 "
		+ ",( SELECT CD_NM "
		+ "		FROM TB_ZZ002 "
		+ "	   WHERE GRP_CD = 'FI065' "
		+ " 	 AND CD = A.RESPONSETYPE) 	AS COL2 "
		+ ",A.SENDDATE 						AS COL3 "
		+ ",A.REGISTDATE 					AS COL4 "
		+ ",A.MESSAGEINFORMATION1 			AS COL5 "
		+ ",A.MESSAGEINFORMATION2 			AS COL6 "
		+ ",A.FUNCTIONCODE 					AS COL7 "
		+ ",B.DOCUMENTIDENTIFIER 			AS COL8 "
		+ ",'' 				AS COL9 "
		+ ",'' 				AS COL10 "
		;

	// 대상테이블
	var param2 =
		  "GENRES_M A, TAXBIL_ISS_M B "
		;

	// 조건절
    var param3 =
		  " AND A.DOCUMENTIDENTIFIER = B.DOCUMENTIDENTIFIER "
		+ " AND B.ORG_VAT_NO = '" + vatNo + "'"
	    ;

	// 정렬
	var param4 =
		  " COL3 DESC "
		;

	// ds_getResposeMessage.DataId =
	// 	"/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC&queryId=dinymicQueryTest" + "&param1=" + param1
	// 	                                                                             + "&param2=" + param2
	// 	                                                                             + "&param3=" + param3
	// 	                                                                             + "&param4=" + param4;
	// ds_getResposeMessage.Reset();

	const strParam = {
              sysCd              : "CommonEBC"           // 시스템코드
            , queryId            : "dinymicQueryTest"    // 쿼리ID
            , param1             : param1                // SELECT
            , param2             : param2                // 대상테이블
            , param3             : param3                // 조건절
            , param4             : param4                // CD
            };

    //데이터셋에 정보설정
    ds_commonCode.setJSON(strParam);

    $c.sbm.execute(sbm_getResposeMessage);    
};
